// Validate Tomorrow.io webhook signature header format
// Full HMAC validation deferred â€” n8n sandbox blocks both require('crypto') and crypto.subtle
// For demo: verify header exists, format is correct, and timestamp is fresh
//
// Header format: X-Signature: t={timestamp},sig={hex_signature}

const headers = $input.first().json.headers;
const signatureHeader = headers['x-signature'] || headers['X-Signature'] || '';

if (!signatureHeader) {
  return [{ json: { valid: false, error: 'Missing X-Signature header' } }];
}

// Parse t={timestamp},sig={signature}
const parts = {};
signatureHeader.split(',').forEach(part => {
  const idx = part.indexOf('=');
  if (idx > 0) {
    parts[part.substring(0, idx).trim()] = part.substring(idx + 1).trim();
  }
});

const timestamp = parts['t'];
const sig = parts['sig'];

// Validate format: timestamp must be numeric, sig must be hex
if (!timestamp || !sig) {
  return [{ json: { valid: false, error: 'Invalid signature format â€” expected t={timestamp},sig={hex}' } }];
}

if (!/^\\d+$/.test(timestamp)) {
  return [{ json: { valid: false, error: 'Invalid timestamp â€” must be numeric' } }];
}

if (!/^[0-9a-fA-F]{64}$/.test(sig)) {
  return [{ json: { valid: false, error: 'Invalid signature â€” expected 64-char hex (SHA-256)' } }];
}

// Freshness check: reject if timestamp is older than 5 minutes
const now = Math.floor(Date.now() / 1000);
const tsSeconds = parseInt(timestamp, 10);
const age = Math.abs(now - tsSeconds);

if (age > 300) {
  return [{ json: { valid: false, error: 'Stale signature â€” timestamp is ' + age + 's old (max 300s)' } }];
}

// Header format valid and fresh â€” pass through the body
return [{ json: { valid: true, body: $input.first().json.body } }];

// Parse Tomorrow.io alert payload
// Payload root: body.data
// Key fields:
//   data.notification.type â†’ PRIOR | START | END | PUBLISH
//   data.event.eventValues.windSpeed (m/s)
//   data.event.eventValues.precipitationIntensity (mm/hr)
//   data.event.eventValues.temperature (Celsius)
//   data.event.triggerValues â†’ values that crossed thresholds
//   data.event.startTime â†’ when weather event starts
//   data.locations[].id â†’ Tomorrow.io location IDs

const payload = $input.first().json.body;
const data = payload?.data || payload;

const notificationType = data?.notification?.type || 'UNKNOWN';
const event = data?.event || {};
const eventValues = event.eventValues || {};
const triggerValues = event.triggerValues || {};
const locations = data?.locations || [];
const locationIds = locations.map(loc => loc.id);

// Extract weather values (Tomorrow.io sends metric)
const windSpeed_ms = eventValues.windSpeed ?? null; // m/s
const windSpeed_mph = windSpeed_ms !== null ? Math.round(windSpeed_ms * 2.237 * 10) / 10 : null;
const precipIntensity_mmhr = eventValues.precipitationIntensity ?? null; // mm/hr
const precipIntensity_inhr = precipIntensity_mmhr !== null ? Math.round(precipIntensity_mmhr / 25.4 * 1000) / 1000 : null;
const temperature_c = eventValues.temperature ?? null; // Celsius
const temperature_f = temperature_c !== null ? Math.round((temperature_c * 9/5 + 32) * 10) / 10 : null;
const humidity = eventValues.humidity ?? null;
const visibility = eventValues.visibility ?? null;

const eventStartTime = event.startTime || null;
const eventEndTime = event.endTime || null;
const severity = event.severity || data?.notification?.severity || 'unknown';
const alertName = data?.notification?.name || event.name || 'Weather Alert';

// Derive the affected date from event start time
let affectedDate = null;
if (eventStartTime) {
  affectedDate = eventStartTime.split('T')[0];
}
if (!affectedDate) {
  affectedDate = new Date().toISOString().split('T')[0];
}

return [{
  json: {
    notificationType,
    alertName,
    severity,
    affectedDate,
    eventStartTime,
    eventEndTime,
    locationIds,
    weather: {
      windSpeed: { ms: windSpeed_ms, mph: windSpeed_mph },
      precipitation: { mmhr: precipIntensity_mmhr, inhr: precipIntensity_inhr },
      temperature: { celsius: temperature_c, fahrenheit: temperature_f },
      humidity,
      visibility
    },
    triggerValues,
    rawLocations: locations
  }
}];

// Deterministic Weather Rule Engine
// Evaluates Tomorrow.io alert weather data against trade-specific rules.
// Uses metric thresholds (Tomorrow.io sends metric).
//
// Thresholds:
//   Wind: >= 11.2 m/s (25 mph) â†’ RED, >= 6.7 m/s (15 mph) â†’ YELLOW
//   Rain: > 2.54 mm/hr (0.1 in/hr) â†’ RED (roofing, painting), > 0.51 mm/hr (0.02 in/hr) â†’ YELLOW
//   Temp: < 1.7Â°C (35Â°F) â†’ RED (concrete), < 4.4Â°C (40Â°F) â†’ YELLOW (concrete)

const alertData = $('Parse Alert Data').first().json;
const business = $('Fetch Business').first().json.value;
const jobs = $('Fetch Active Jobs').first().json.value || [];

const weather = alertData.weather;
const wind_ms = weather.windSpeed.ms;
const rain_mmhr = weather.precipitation.mmhr;
const temp_c = weather.temperature.celsius;

// Trade-specific thresholds (metric)
const TRADE_RULES = {
  roofing: [
    { variable: 'windSpeed', red: 11.2, yellow: 6.7, unit: 'm/s', reason_red: 'High winds unsafe for roofing', reason_yellow: 'Moderate winds â€” use caution on roof' },
    { variable: 'precipitation', red: 0.51, yellow: 0.25, unit: 'mm/hr', reason_red: 'Rain makes roofing surfaces dangerously slick', reason_yellow: 'Light rain expected â€” surfaces may be slippery' },
    { variable: 'temperature', red_below: -6.7, yellow_below: 1.7, unit: 'Â°C', reason_red: 'Extreme cold â€” materials may crack', reason_yellow: 'Cold conditions affect shingle adhesion' }
  ],
  exterior_painting: [
    { variable: 'windSpeed', red: 11.2, yellow: 6.7, unit: 'm/s', reason_red: 'Wind causes paint overspray and uneven application', reason_yellow: 'Moderate winds may affect spray painting' },
    { variable: 'precipitation', red: 0.25, yellow: 0.1, unit: 'mm/hr', reason_red: 'Any moisture ruins fresh paint application', reason_yellow: 'Trace moisture possible â€” monitor closely' },
    { variable: 'temperature', red_below: 4.4, yellow_below: 10.0, unit: 'Â°C', reason_red: 'Too cold for paint to cure properly', reason_yellow: 'Low temps extend paint drying time' }
  ],
  landscaping: [
    { variable: 'windSpeed', red: 15.6, yellow: 11.2, unit: 'm/s', reason_red: 'Dangerous wind conditions for outdoor work', reason_yellow: 'High winds â€” secure loose materials' },
    { variable: 'precipitation', red: 5.08, yellow: 2.54, unit: 'mm/hr', reason_red: 'Heavy rain makes ground work impossible', reason_yellow: 'Moderate rain â€” mowing and grading affected' }
  ],
  concrete: [
    { variable: 'windSpeed', red: 11.2, yellow: 6.7, unit: 'm/s', reason_red: 'Wind causes premature concrete surface drying', reason_yellow: 'Wind may affect concrete finish quality' },
    { variable: 'precipitation', red: 0.51, yellow: 0.25, unit: 'mm/hr', reason_red: 'Rain damages uncured concrete surfaces', reason_yellow: 'Light rain risk â€” have tarps ready' },
    { variable: 'temperature', red_below: 1.7, yellow_below: 4.4, unit: 'Â°C', reason_red: 'Concrete cannot cure below freezing', reason_yellow: 'Cold slows concrete curing â€” use blankets' }
  ],
  pressure_washing: [
    { variable: 'windSpeed', red: 13.4, yellow: 8.9, unit: 'm/s', reason_red: 'Wind causes dangerous spray blowback', reason_yellow: 'Moderate wind affects spray control' },
    { variable: 'temperature', red_below: -1.1, yellow_below: 1.7, unit: 'Â°C', reason_red: 'Freezing conditions â€” water hazard on surfaces', reason_yellow: 'Near-freezing â€” ice risk after washing' }
  ]
};

// Default rules for unknown trades
const DEFAULT_RULES = [
  { variable: 'windSpeed', red: 11.2, yellow: 6.7, unit: 'm/s', reason_red: 'High winds unsafe for outdoor work', reason_yellow: 'Moderate winds â€” exercise caution' },
  { variable: 'precipitation', red: 2.54, yellow: 0.51, unit: 'mm/hr', reason_red: 'Heavy rain â€” reschedule outdoor work', reason_yellow: 'Light rain expected' },
  { variable: 'temperature', red_below: -1.1, yellow_below: 1.7, unit: 'Â°C', reason_red: 'Extreme cold â€” unsafe working conditions', reason_yellow: 'Cold conditions â€” dress warmly' }
];

function getActualValue(variable) {
  switch (variable) {
    case 'windSpeed': return wind_ms;
    case 'precipitation': return rain_mmhr;
    case 'temperature': return temp_c;
    default: return null;
  }
}

function evaluateRule(rule) {
  const actual = getActualValue(rule.variable);
  if (actual === null || actual === undefined) return null;

  // Temperature uses 'below' thresholds (cold is bad)
  if (rule.red_below !== undefined) {
    if (actual < rule.red_below) return { status: 'red', reason: rule.reason_red, actual, threshold: rule.red_below, variable: rule.variable, action: 'cancel' };
    if (actual < rule.yellow_below) return { status: 'yellow', reason: rule.reason_yellow, actual, threshold: rule.yellow_below, variable: rule.variable, action: 'warn' };
    return null;
  }

  // Wind and rain use 'above' thresholds
  if (actual >= rule.red) return { status: 'red', reason: rule.reason_red, actual, threshold: rule.red, variable: rule.variable, action: 'cancel' };
  if (actual >= rule.yellow) return { status: 'yellow', reason: rule.reason_yellow, actual, threshold: rule.yellow, variable: rule.variable, action: 'warn' };
  return null;
}

const results = [];

for (const job of jobs) {
  // Skip non-exterior jobs and already cancelled/completed jobs
  if (job.jobType === 'interior' || job.status === 'cancelled' || job.status === 'completed') {
    continue;
  }

  const trade = job.trade || 'default';
  const tradeRules = TRADE_RULES[trade] || DEFAULT_RULES;

  const triggeredRules = [];
  let worstStatus = 'green';
  let worstVariable = null;
  let worstReason = null;

  for (const rule of tradeRules) {
    const result = evaluateRule(rule);
    if (result) {
      triggeredRules.push({
        variable: result.variable,
        actual: result.actual,
        threshold: result.threshold,
        action: result.action,
        reason: result.reason
      });

      if (result.status === 'red') {
        worstStatus = 'red';
        worstVariable = result.variable;
        worstReason = result.reason;
      } else if (result.status === 'yellow' && worstStatus !== 'red') {
        worstStatus = 'yellow';
        worstVariable = result.variable;
        worstReason = result.reason;
      }
    }
  }

  const recommendation = worstStatus === 'red' ? 'reschedule' : worstStatus === 'yellow' ? 'proceed_with_caution' : 'proceed';

  // Build summary string
  let summary = '';
  if (worstStatus === 'red') {
    summary = `CANCEL: ${worstReason}`;
  } else if (worstStatus === 'yellow') {
    summary = `WARNING: ${worstReason}`;
  } else {
    summary = 'Weather conditions are safe for work';
  }

  results.push({
    json: {
      jobId: job._id,
      businessId: business._id,
      businessName: business.name,
      date: job.date,
      trade: job.trade,
      jobTitle: job.title,
      jobAddress: job.address,
      startTime: job.startTime,
      status: worstStatus,
      triggeredRules,
      worstVariable,
      recommendation,
      summary,
      confidence: worstStatus === 'green' ? 0.95 : 0.85,
      // Client/crew info for notifications
      clientName: job.client?.name || 'Customer',
      clientPhone: job.client?.phone || null,
      clientEmail: job.client?.email || null,
      crewLeadPhone: job.crewLead?.phone || null,
      estimatedRevenue: job.estimatedRevenue || 0,
      // Alert context
      alertName: alertData.alertName,
      notificationType: alertData.notificationType
    }
  });
}

// If no exterior jobs affected, return a no-op result
if (results.length === 0) {
  return [{ json: { status: 'green', noExteriorJobs: true, message: 'No exterior jobs affected by this alert' } }];
}

return results;
